            <h3>Results:</h3>
            <div id="resultsDisplay"></div>

            <h3>Explanation:</h3>
            <p id="explanation"></p>
        </div>
    </div>

    <script>
        // In-memory product database (simulated)
        const products = [
            { id: 1, name: "Laptop", price: 999 },
            { id: 2, name: "Phone", price: 499 },
            { id: 3, name: "Tablet", price: 299 },
            { id: 4, name: "Monitor", price: 199 }
        ];

        const searchButton = document.getElementById('searchButton');
        const searchInput = document.getElementById('searchInput');
        const queryDisplay = document.getElementById('queryDisplay');
        const resultsDisplay = document.getElementById('resultsDisplay');
        const explanation = document.getElementById('explanation');

        searchButton.addEventListener('click', () => {
            const mode = document.querySelector('input[name="mode"]:checked').value;
            const userInput = searchInput.value.trim();  // Get user input
            let queryString = '';  // The simulated SQL query
            let results = [];  // Simulated results
            let explanationText = '';  // Explanation of what happened

            if (mode === 'vulnerable') {
                // Vulnerable mode: String concatenation
                queryString = `SELECT * FROM products WHERE name = '${userInput}'`;  // Directly concatenate input

                // Simulate execution: Check if input contains injection-like patterns (e.g., ' OR)
                if (userInput.toLowerCase().includes(' or ') || userInput.includes('--') || userInput.includes(';')) {
                    // Simulate injection success: Return all products (as if the query was altered)
                    results = products;
                    explanationText = 'Injection detected! In vulnerable mode, the input altered the query, returning all products instead of a filtered result.';
                } else {
                    // Normal case: Filter by exact match
                    results = products.filter(product => product.name === userInput);
                    explanationText = 'No injection detected. Results are filtered by exact match.';
                }
            } else if (mode === 'safe') {
                // Safe mode: Parameterized query simulation
                // Treat input as a literal parameter and escape it (e.g., by wrapping in quotes and escaping special chars)
                const escapedInput = userInput.replace(/'/g, "''");  // Simple escaping for single quotes
                queryString = `SELECT * FROM products WHERE name = @param`;  // Parameterized placeholder
                const fullQueryExplanation = `Actual executed query: SELECT * FROM products WHERE name = '${escapedInput}'`;  // Show what it would look like

                // Simulate safe execution: Always filter by exact match on the escaped input
                results = products.filter(product => product.name === escapedInput);  // Use escaped input for matching
                explanationText = 'Safe mode uses parameterization, so the input is treated as a literal value. Injections are ignored, and only exact matches are returned.';

                queryDisplay.textContent = fullQueryExplanation;  // Display the parameterized version
                return;  // Skip the rest for safe mode
            }

            // Display the query and results
            queryDisplay.textContent = queryString;
            if (results.length > 0) {
                resultsDisplay.innerHTML = results.map(product => 
                    `<p>ID: ${product.id}, Name: ${product.name}, Price: $${product.price}</p>`
                ).join('');
            } else {
                resultsDisplay.innerHTML = '<p>No results found.</p>';
            }
            explanation.textContent = explanationText;
        });
    </script>
